import { Component, OnInit, inject } from '@angular/core';
import { FormBuilder, FormGroup, Validators, AbstractControl, ValidationErrors, ValidatorFn } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { SignupRequest } from '../../models/auth.model';

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.scss']
})
export class RegisterComponent implements OnInit {
  registerForm!: FormGroup;
  loading = false;
  submitted = false;
  error: string | null = null;
  showPassword = false;
  showConfirmPassword = false;
  passwordStrength = 0;

  private formBuilder = inject(FormBuilder);
  private authService = inject(AuthService);
  private router = inject(Router);

  ngOnInit(): void {
    // Redirect to dashboard if already logged in
    if (this.authService.isAuthenticated()) {
      this.router.navigate(['/tasks']);
    }

    this.initializeForm();
  }

  initializeForm(): void {
    this.registerForm = this.formBuilder.group(
      {
        username: ['', [Validators.required, Validators.minLength(3), Validators.maxLength(50)]],
        email: ['', [Validators.required, Validators.email]],
        password: ['', [Validators.required, Validators.minLength(8), Validators.maxLength(128)]],
        confirmPassword: ['', Validators.required]
      },
      {
        validators: this.passwordMatchValidator()
      }
    );

    // Monitor password field for strength calculation
    this.registerForm.get('password')?.valueChanges.subscribe(() => {
      this.calculatePasswordStrength();
    });
  }

  passwordMatchValidator(): ValidatorFn {
    return (formGroup: AbstractControl): ValidationErrors | null => {
      const password = formGroup.get('password')?.value;
      const confirmPassword = formGroup.get('confirmPassword')?.value;

      if (!password || !confirmPassword) {
        return null;
      }

      return password !== confirmPassword ? { passwordMismatch: true } : null;
    };
  }

  get f() {
    return this.registerForm.controls;
  }

  calculatePasswordStrength(): void {
    const password = this.f['password'].value;
    if (!password) {
      this.passwordStrength = 0;
      return;
    }

    let strength = 0;
    if (password.length >= 8) strength += 1;
    if (password.length >= 12) strength += 1;
    if (/[a-z]/.test(password) && /[A-Z]/.test(password)) strength += 1;
    if (/\d/.test(password)) strength += 1;
    if (/[\W_]/.test(password)) strength += 1;

    this.passwordStrength = Math.min(strength, 5);
  }

  getPasswordStrengthText(): string {
    switch (this.passwordStrength) {
      case 1:
        return 'Weak';
      case 2:
        return 'Fair';
      case 3:
        return 'Good';
      case 4:
        return 'Strong';
      case 5:
        return 'Very Strong';
      default:
        return '';
    }
  }

  getPasswordStrengthClass(): string {
    switch (this.passwordStrength) {
      case 1:
        return 'weak';
      case 2:
        return 'fair';
      case 3:
        return 'good';
      case 4:
        return 'strong';
      case 5:
        return 'very-strong';
      default:
        return '';
    }
  }

  onSubmit(): void {
    this.submitted = true;
    this.error = null;

    // Stop if form is invalid
    if (this.registerForm.invalid) {
      return;
    }

    this.loading = true;
    this.disableForm();

    const signupRequest: SignupRequest = {
      username: this.f['username'].value,
      email: this.f['email'].value,
      password: this.f['password'].value,
      confirmPassword: this.f['confirmPassword'].value
    };

    this.authService.signup(signupRequest).subscribe({
      next: (response) => {
        console.log('Signup successful:', response);
        this.loading = false;
        this.router.navigate(['/auth/login']);
      },
      error: (error) => {
        console.error('Signup failed:', error);
        this.error = error.message || 'Signup failed. Please try again.';
        this.loading = false;
        this.enableForm();
      }
    });
  }

  private disableForm(): void {
    Object.keys(this.registerForm.controls).forEach(key => {
      this.registerForm.get(key)?.disable();
    });
  }

  private enableForm(): void {
    Object.keys(this.registerForm.controls).forEach(key => {
      this.registerForm.get(key)?.enable();
    });
  }

  togglePasswordVisibility(): void {
    this.showPassword = !this.showPassword;
  }

  toggleConfirmPasswordVisibility(): void {
    this.showConfirmPassword = !this.showConfirmPassword;
  }

  goToLogin(): void {
    this.router.navigate(['/auth/login']);
  }
}
<div class="register-container">
  <div class="register-card">
    <div class="register-header">
      <h1>Create Account</h1>
      <p>Join Task Flow and organize your day with clarity</p>
    </div>

    <form [formGroup]="registerForm" (ngSubmit)="onSubmit()" class="register-form">
      <!-- Error Message -->
      @if (error) {
        <div class="alert alert-error">
          <span class="alert-icon">⚠️</span>
          <span>{{ error }}</span>
        </div>
      }

      <!-- Username Field -->
      <div class="form-group">
        <label for="username" class="form-label">Username</label>
        <input
          type="text"
          id="username"
          formControlName="username"
          class="form-control"
          [class.is-invalid]="submitted && f['username'].errors"
          placeholder="Choose a username"
        />
        @if (submitted && f['username'].errors) {
          <div class="field-error">
            @if (f['username'].errors['required']) {
              <span>Username is required</span>
            }
            @if (f['username'].errors['minlength']) {
              <span>Username must be at least 3 characters</span>
            }
            @if (f['username'].errors['maxlength']) {
              <span>Username can't exceed 50 characters</span>
            }
          </div>
        }
      </div>

      <!-- Email Field -->
      <div class="form-group">
        <label for="email" class="form-label">Email Address</label>
        <input
          type="email"
          id="email"
          formControlName="email"
          class="form-control"
          [class.is-invalid]="submitted && f['email'].errors"
          placeholder="Enter your email"
        />
        @if (submitted && f['email'].errors) {
          <div class="field-error">
            @if (f['email'].errors['required']) {
              <span>Email is required</span>
            }
            @if (f['email'].errors['email']) {
              <span>Please enter a valid email address</span>
            }
          </div>
        }
      </div>

      <!-- Password Field -->
      <div class="form-group">
        <label for="password" class="form-label">Password</label>
        <div class="password-input-group">
          <input
            [type]="showPassword ? 'text' : 'password'"
            id="password"
            formControlName="password"
            class="form-control"
            [class.is-invalid]="submitted && f['password'].errors"
            placeholder="Create a strong password"
            (input)="calculatePasswordStrength()"
          />
          <button
            type="button"
            class="password-toggle"
            (click)="togglePasswordVisibility()"
            [attr.aria-label]="showPassword ? 'Hide password' : 'Show password'"
            [attr.title]="showPassword ? 'Hide password' : 'Show password'"
          >
            @if (!showPassword) {
              <svg class="password-toggle-icon" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                <path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.269 2.943 9.542 7-1.273 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7Z" />
                <circle cx="12" cy="12" r="3" />
              </svg>
            } @else {
              <svg class="password-toggle-icon" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                <path d="m3 3 18 18" />
                <path d="M10.58 10.58a2 2 0 0 0 2.83 2.83" />
                <path d="M9.88 5.09A10.77 10.77 0 0 1 12 5c4.478 0 8.269 2.943 9.542 7a11.03 11.03 0 0 1-3.03 4.35" />
                <path d="M6.61 6.61A11.03 11.03 0 0 0 2.458 12c1.273 4.057 5.064 7 9.542 7 1.61 0 3.13-.38 4.47-1.05" />
              </svg>
            }
          </button>
        </div>

        <!-- Password Strength Indicator -->
        @if (f['password'].value) {
          <div class="password-strength">
            <div class="strength-bar-container">
              <div 
                class="strength-bar" 
                [ngClass]="'strength-' + getPasswordStrengthClass()"
                [style.width.%]="(passwordStrength / 5) * 100"
              ></div>
            </div>
            <span class="strength-text" [ngClass]="'strength-' + getPasswordStrengthClass()">
              {{ getPasswordStrengthText() }}
            </span>
          </div>
        }

        @if (submitted && f['password'].errors) {
          <div class="field-error">
            @if (f['password'].errors['required']) {
              <span>Password is required</span>
            }
            @if (f['password'].errors['minlength']) {
              <span>Password must be at least 8 characters</span>
            }
            @if (f['password'].errors['maxlength']) {
              <span>Password can't exceed 128 characters</span>
            }
          </div>
        }

        <p class="password-hint">Use a mix of uppercase, lowercase, numbers, and special characters</p>
      </div>

      <!-- Confirm Password Field -->
      <div class="form-group">
        <label for="confirmPassword" class="form-label">Confirm Password</label>
        <div class="password-input-group">
          <input
            [type]="showConfirmPassword ? 'text' : 'password'"
            id="confirmPassword"
            formControlName="confirmPassword"
            class="form-control"
            [class.is-invalid]="(submitted || f['confirmPassword'].touched || f['confirmPassword'].dirty) && (f['confirmPassword'].errors || registerForm.errors?.['passwordMismatch'])"
            placeholder="Confirm your password"
          />
          <button
            type="button"
            class="password-toggle"
            (click)="toggleConfirmPasswordVisibility()"
            [attr.aria-label]="showConfirmPassword ? 'Hide confirm password' : 'Show confirm password'"
            [attr.title]="showConfirmPassword ? 'Hide confirm password' : 'Show confirm password'"
          >
            @if (!showConfirmPassword) {
              <svg class="password-toggle-icon" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                <path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.269 2.943 9.542 7-1.273 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7Z" />
                <circle cx="12" cy="12" r="3" />
              </svg>
            } @else {
              <svg class="password-toggle-icon" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                <path d="m3 3 18 18" />
                <path d="M10.58 10.58a2 2 0 0 0 2.83 2.83" />
                <path d="M9.88 5.09A10.77 10.77 0 0 1 12 5c4.478 0 8.269 2.943 9.542 7a11.03 11.03 0 0 1-3.03 4.35" />
                <path d="M6.61 6.61A11.03 11.03 0 0 0 2.458 12c1.273 4.057 5.064 7 9.542 7 1.61 0 3.13-.38 4.47-1.05" />
              </svg>
            }
          </button>
        </div>
        @if ((submitted || f['confirmPassword'].touched || f['confirmPassword'].dirty) && (f['confirmPassword'].errors || registerForm.errors?.['passwordMismatch'])) {
          <div class="field-error">
            @if (f['confirmPassword'].errors?.['required']) {
              <span>Confirm password is required</span>
            }
            @if (registerForm.errors?.['passwordMismatch']) {
              <span>Passwords do not match</span>
            }
          </div>
        }
      </div>

      <!-- Submit Button -->
      <button
        type="submit"
        class="btn btn-primary btn-block"
        [disabled]="loading || registerForm.invalid"
      >
        @if (!loading) {
          <span>Create Account</span>
        } @else {
          <span class="spinner">
            <span class="spinner-dot"></span> Creating account...
          </span>
        }
      </button>
    </form>

    <!-- Login Link -->
    <div class="register-footer">
      <p>Already have an account?
        <a href="javascript:void(0)" (click)="goToLogin()" class="link">Sign in here</a>
      </p>
    </div>
  </div>
</div>
